import Foundation

/// Filters an array of strings to include only those that contain at least one numeric digit.
///
/// - Parameter inputArray: An array of strings to be filtered.
/// - Returns: A new array containing only strings that have at least one digit.
func filterStringsWithDigits(inputArray: [String]) -> [String] {
    // Filter the input array to include only strings with at least one digit
    let resultArray = inputArray.filter { string in
        // Check if the string contains any numeric digits
        let containsDigit = string.rangeOfCharacter(from: .decimalDigits) != nil
        return containsDigit
    }

    return resultArray
}

