Certainly! Below is a C++ program that uses dynamic programming to find the length of the longest increasing subsequence (LIS) in a given sequence of integers. The program will accept user input for the length of the sequence and the values in the sequence, and then it will output the length of the longest increasing subsequence.

```cpp
#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

int longestIncreasingSubsequenceLength(const vector<int>& nums) {
    int n = nums.size();
    if (n == 0) return 0;

    // Initialize the dp array where dp[i] represents the length of the longest increasing subsequence
    // ending with nums[i]
    vector<int> dp(n, 1);

    // Build the dp array
    for (int i = 1; i < n; ++i) {
        for (int j = 0; j < i; ++j) {
            if (nums[i] > nums[j]) {
                dp[i] = max(dp[i], dp[j] + 1);
            }
        }
    }

    // The length of the longest increasing subsequence will be the maximum value in dp array
    return *max_element(dp.begin(), dp.end());
}

int main() {
    int n;
    cout << "Enter the number of elements in the sequence: ";
    cin >> n;

    vector<int> sequence(n);
    cout << "Enter the elements of the sequence: ";
    for (int i = 0; i < n; ++i) {
        cin >> sequence[i];
    }

    int lisLength = longestIncreasingSubsequenceLength(sequence);
    cout << "The length of the longest increasing subsequence is: " << lisLength << endl;

    return 0;
}
```

